export type Post = {
  id: string;
  title: string;
  userId: string;
};

export type User = {
  id: string;
  name: string;
  posts: Post[];
};

export const users: User[] = [
  {
    id: "1",
    name: "Ada",
    posts: [
      { id: "p1", title: "Ada Post 1", userId: "1" },
      { id: "p2", title: "Ada Post 2", userId: "1" },
    ],
  },
  {
    id: "2",
    name: "Bao",
    posts: [
      { id: "p1", title: "Bao Post 1", userId: "2" },
      { id: "p2", title: "Bao Post 2", userId: "2" },
    ],
  },
  {
    id: "3",
    name: "Cyrus",
    posts: [
      { id: "p1", title: "Cyrus Post 1", userId: "3" },
      { id: "p2", title: "Cyrus Post 2", userId: "3" },
    ],
  },
];

export function getUserById(id: string): User | undefined {
  return users.find((u) => u.id === id);
}

export function getPostById(
  userId: string,
  postId: string
): Post | undefined {
  const user = getUserById(userId);
  return user?.posts.find((p) => p.id === postId);
}

import { linkFor } from "rwsdk/router";
import type * as Worker from "../../worker";

type App = typeof Worker.default;

export const link = linkFor<App>();

import { users } from "@/app/shared/seed";
import { link } from "@/app/shared/links";

export const UsersPage = () => {
  return (
    <main>
      <h1>Users</h1>
      <ul>
        {users.map((user) => (
          <li key={user.id}>
            <a href={link("/users/:id", { id: user.id })}>{user.name}</a>
          </li>
        ))}
      </ul>
    </main>
  );
};

import { RequestInfo } from "rwsdk/worker";
import { getUserById } from "@/app/shared/seed";
import { link } from "@/app/shared/links";

export const UserDetailPage = ({
  params,
}: RequestInfo<{ id: string }>) => {
  const user = getUserById(params.id);

  if (!user) {
    return (
      <main>
        <h1>User not found</h1>
        <a href={link("/users")}>Back to Users</a>
      </main>
    );
  }

  return (
    <main>
      <h1>{user.name}</h1>
      <p>User ID: {user.id}</p>
      <h2>Posts</h2>
      <ul>
        {user.posts.map((post) => (
          <li key={post.id}>
            <a
              href={link("/users/:id/posts/:postId", {
                id: user.id,
                postId: post.id,
              })}
            >
              {post.title}
            </a>
          </li>
        ))}
      </ul>
      <a href={link("/users")}>Back to Users</a>
    </main>
  );
};

import { RequestInfo } from "rwsdk/worker";
import { getUserById, getPostById } from "@/app/shared/seed";
import { link } from "@/app/shared/links";

export const PostDetailPage = ({
  params,
}: RequestInfo<{ id: string; postId: string }>) => {
  const user = getUserById(params.id);
  const post = getPostById(params.id, params.postId);

  if (!user || !post) {
    return (
      <main>
        <h1>Post not found</h1>
        <a href={link("/users")}>Back to Users</a>
      </main>
    );
  }

  return (
    <main>
      <h1>{post.title}</h1>
      <p>User ID: {params.id}</p>
      <p>Post ID: {params.postId}</p>
      <a href={link("/users/:id", { id: params.id })}>
        Back to {user.name}
      </a>
    </main>
  );
};

import { users } from "@/app/shared/seed";
import { link } from "@/app/shared/links";

export const Home = () => {
  return (
    <main>
      <h1>Home</h1>
      <h2>Users</h2>
      <ul>
        {users.map((user) => (
          <li key={user.id}>
            <a href={link("/users/:id", { id: user.id })}>{user.name}</a>
          </li>
        ))}
      </ul>
      <a href={link("/users")}>View all users</a>
    </main>
  );
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { UsersPage } from "@/app/pages/users";
import { UserDetailPage } from "@/app/pages/userDetail";
import { PostDetailPage } from "@/app/pages/postDetail";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  render(Document, [
    route("/", Home),
    route("/users", UsersPage),
    route("/users/:id", UserDetailPage),
    route("/users/:id/posts/:postId", PostDetailPage),
  ]),
]);
